import { Router } from "express";
import PostService from "./post.service.js";
import { schema } from "../../common/middleware/schema/schema.js";
import { authentication } from "../../common/middleware/auth.middleware.js";
import multerCloud from "../../common/middleware/multer.cloud.js";
import { Store_Enum } from "../../common/enum/multer.enum.js";
import { createPostSchema, updatePostSchema } from "../../common/middleware/schema/post.schema.js";
import commentRouter from "../comments/comment.controller.js";
const postRouter = Router({ caseSensitive: true, strict: true });
postRouter.post("/", authentication, multerCloud({ storeType: Store_Enum.memory }).array("attachment"), schema(createPostSchema), PostService.createPost);
postRouter.get("/", authentication, PostService.getPost);
postRouter.post("/:postId/react", authentication, PostService.reactOnPost);
postRouter.put("/:postId", authentication, schema(updatePostSchema), PostService.updatePost);
postRouter.delete("/:postId", authentication, PostService.deletePost);
postRouter.use("/:postId/comments", commentRouter);
export default postRouter;
